import java.io.*;class Main{static int pigs(int b,int d,int t){int states=t/d+1,p=0,cap=1;while(cap<b){p++;cap*=states;}return p;}public static void main(String[]args)throws Exception{String text=new String(System.in.readAllBytes()).trim();if(text.isEmpty())return;String[]v=text.split("\\s+");int idx=0,tc=Integer.parseInt(v[idx++]);StringBuilder out=new StringBuilder();for(int i=0;i<tc;i++){int b=Integer.parseInt(v[idx++]),d=Integer.parseInt(v[idx++]),t=Integer.parseInt(v[idx++]);if(i>0)out.append("\n\n");out.append(pigs(b,d,t));}System.out.print(out);}}
